class Solution:
    def maxNumber(self, nums1, nums2, k):
        from itertools import combinations
        m, n = len(nums1), len(nums2)
        best = None
        for i in range(max(0, k - n), min(k, m) + 1):
            j = k - i
            # Pick i indices from nums1 and j from nums2, maintaining relative order
            # For brute force, enumerate all C(m,i)*C(n,j) combinations — cap sizes
            sub1_best = None
            for idxs in combinations(range(m), i):
                s = [nums1[x] for x in idxs]
                if sub1_best is None or s > sub1_best:
                    sub1_best = s
            sub2_best = None
            for idxs in combinations(range(n), j):
                s = [nums2[x] for x in idxs]
                if sub2_best is None or s > sub2_best:
                    sub2_best = s
            if sub1_best is None:
                sub1_best = []
            if sub2_best is None:
                sub2_best = []
            # merge
            merged = []
            a, b = list(sub1_best), list(sub2_best)
            while a or b:
                if a >= b:
                    merged.append(a.pop(0))
                else:
                    merged.append(b.pop(0))
            if best is None or merged > best:
                best = merged
        return best if best else []

