var maxNumber = function(nums1, nums2, k) {
    function maxSubseq(nums, t) {
        let drop = nums.length - t;
        const stack = [];
        for (const d of nums) {
            while (drop > 0 && stack.length > 0 && stack[stack.length - 1] < d) {
                stack.pop();
                drop--;
            }
            stack.push(d);
        }
        return stack.slice(0, t);
    }
    function geq(a, ai, b, bi) {
        while (ai < a.length && bi < b.length) {
            if (a[ai] !== b[bi]) return a[ai] > b[bi];
            ai++; bi++;
        }
        return (a.length - ai) >= (b.length - bi);
    }
    function merge(a, b) {
        const result = [];
        let i = 0, j = 0;
        while (i < a.length || j < b.length) {
            if (geq(a, i, b, j)) result.push(a[i++]);
            else result.push(b[j++]);
        }
        return result;
    }
    const m = nums1.length, n = nums2.length;
    let best = [];
    for (let i = Math.max(0, k - n); i <= Math.min(k, m); i++) {
        const s1 = maxSubseq(nums1, i);
        const s2 = maxSubseq(nums2, k - i);
        const candidate = merge(s1, s2);
        if (candidate.length > best.length || (candidate.length === best.length && geq(candidate, 0, best, 0) && !geq(best, 0, candidate, 0))) {
            best = candidate;
        }
    }
    return best;
};
